-- 第三步：验证数据
SELECT province, year, COUNT(*) as records, MIN(min_score) as min_score, 
MAX(min_score) as max_score FROM major_scores WHERE province = '海南' 
GROUP BY province, year;

-- 第四步：按学校统计
SELECT school_name, COUNT(*) as majors FROM major_scores WHERE province = '海南' 
GROUP BY school_name ORDER BY school_name LIMIT 20;

-- 第五步：验证major_description字段
SELECT COUNT(*) as total_with_description FROM major_scores 
WHERE province = '海南' AND major_description IS NOT NULL AND major_description != '';